using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerToolType]
public static class ApiTools
{
    [McpServerTool, Description("Fetches a list of objects from the external API.")]
    public static async Task<string> GetObjects(IHttpClientFactory httpClientFactory)
    {
        using var client = httpClientFactory.CreateClient("Api");
        var response = await client.GetAsync("objects");
        response.EnsureSuccessStatusCode();

        using var doc = await JsonDocument.ParseAsync(await response.Content.ReadAsStreamAsync());
        return JsonSerializer.Serialize(doc, new JsonSerializerOptions { WriteIndented = true });
    }

    [McpServerTool, Description("Fetches a single object by its ID from the external API.")]
    public static async Task<string> GetObjectById(
        IHttpClientFactory httpClientFactory,
        [Description("The ID of the object to retrieve.")] string id)
    {
        using var client = httpClientFactory.CreateClient("Api");
        var response = await client.GetAsync($"objects/{id}");
        response.EnsureSuccessStatusCode();

        using var doc = await JsonDocument.ParseAsync(await response.Content.ReadAsStreamAsync());
        return JsonSerializer.Serialize(doc, new JsonSerializerOptions { WriteIndented = true });
    }
}

using System.ComponentModel;
using ModelContextProtocol.Protocol;
using ModelContextProtocol.Server;

[McpServerPromptType]
public static class SummarizePrompt
{
    [McpServerPrompt, Description("Generates a summarization prompt for a given text.")]
    public static IList<PromptMessage> Summarize(
        [Description("The text to summarize.")] string text,
        [Description("Desired summary style: brief, detailed, or bullet-points.")] string style = "brief")
    {
        return
        [
            new PromptMessage
            {
                Role = Role.User,
                Content = new Content
                {
                    Type = "text",
                    Text = $"Summarize the following text in a {style} style:\n\n{text}"
                }
            }
        ];
    }
}

